/** Message from unwrap(Error) or friendly fallback — ref form-api-error-handling.md */
import { isApiConnectionError } from '@linm-soft-org/linm-web-common-components';

export function getApiErrorMessage(err: unknown, fallback: string): string {
  if (isApiConnectionError(err)) return err.message;
  if (err instanceof Error && err.message.trim()) return err.message;
  return fallback;
}
